sql:
SELECT category_name 
FROM gamer_categories 
WHERE is_active = 1;

SELECT category_name
FROM gamer_categories
WHERE category_id = 1;

SELECT AVG(rating) AS average_rating
FROM game_ratings
WHERE game_title = '0';

